    12	    Denied { tool_name: String, reason: String },
    13	}
    14	
    15	/// AuditSink wrapper that enforces a tool allowlist at the Orbit layer.
    16	///
    17	/// Usage: Build the inner sink (e.g. JsonlFileSink / InMemorySink), wrap it
    18	/// with an EnforcedAuditSink at construction, and pass the wrapper into
    19	/// AgentLoop::run via the audit parameter. The wrapper intercepts
    20	/// ToolCallRequested events, checks the name against the allowlist, and (on
    21	/// deny) substitutes a PolicyDenial event and signals the caller to
    22	/// terminate.
    23	pub struct EnforcedAuditSink {
    24	    inner: Arc<dyn AuditSink>,
    25	    allowlist: Vec<String>,
    26	    writer: Arc<V2AuditWriter>,
    27	    run_id: String,
    28	    session_id: String,
    29	    tripped: Mutex<Option<EnforcementDecision>>,
    30	}
    31	
    32	impl EnforcedAuditSink {
    33	    pub fn new(
    34	        inner: Arc<dyn AuditSink>,
    35	        allowlist: Vec<String>,
    36	        writer: Arc<V2AuditWriter>,
    37	        run_id: impl Into<String>,
    38	        session_id: impl Into<String>,
    39	    ) -> Self {
    40	        Self {
    41	            inner,
    42	            allowlist,
    43	            writer,
    44	            run_id: run_id.into(),
    45	            session_id: session_id.into(),
    46	            tripped: Mutex::new(None),
    47	        }
    48	    }
    49	
    50	    pub fn tripped(&self) -> Option<EnforcementDecision> {
    51	        self.tripped.lock().expect("tripped mutex").clone()
    52	    }
    53	}
    54	
    55	impl AuditSink for EnforcedAuditSink {
    56	    fn emit(&self, event: &LoopAuditEvent) {
    57	        // Two paths can trigger the denial:
    58	        //
    59	        // 1. `AgentLoop` enforces the allowlist internally BEFORE dispatching
    60	        //    a `ToolCallRequested` event and emits its own `PolicyDenial`.
    61	        //    When we see a `PolicyDenial`, we mirror it into a §7
    62	        //    `tool.denied` envelope event so the higher-level trail records
    63	        //    the policy outcome alongside the loop-level event.
    64	        //
    65	        // 2. A caller that bypasses the loop's own check could still emit a
    66	        //    `ToolCallRequested` for a tool we shouldn't allow — we catch
    67	        //    that here too and synthesize both a §7 `tool.denied` envelope
    68	        //    event and a loop-level `PolicyDenial`.
