2\t            allowlist,\n    43\t            writer,\n    44\t            run_id: run_id.into(),\n    45\t            session_id: session_id.into(),\n    46\t            tripped: Mutex::new(None),\n    47\t        }\n    48\t    }\n    49\t\n    50\t    pub fn tripped(&self) -> Option<EnforcementDecision> {\n    51\t        self.tripped.lock().expect(\"tripped mutex\").clone()\n    52\t    }\n    53\t}\n    54\t\n    55\timpl AuditSink for EnforcedAuditSink {\n    56\t    fn emit(&self, event: &LoopAuditEvent) {\n    57\t        // Two paths can trigger the denial:\n    58\t        //\n    59\t        // 1. `AgentLoop` enforces the allowlist internally BEFORE dispatching\n    60\t        //    a `ToolCallRequested` event and emits its own `PolicyDenial`.\n    61\t        //    When we see a `PolicyDenial`, we mirror it into a §7\n    62\t        //    `tool.denied` envelope event so the higher-level trail records\n    63\t        //    the policy outcome alongside the loop-level event.\n    64\t        //\n    65\t        // 2. A caller that bypasses the loop's own check could still emit a\n    66\t        //    `ToolCallRequested` for a tool we shouldn't allow — we catch\n    67\t        //    that here too and synthesize both a §7 `tool.denied` envelope\n    68\t        //    event and a loop-level `PolicyDenial`.\n    69\t        match event {\n    70\t            LoopAuditEvent::PolicyDenial {\n    71\t                tool_name, reason, ..\n    72\t            } => {\n    73\t                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {\n    74\t                    tool_name: tool_name.clone(),\n    75\t                    reason: reason.clone(),\n    76\t                });\n    77\t                *self.tripped.lock().expect(\"tripped mutex\") = Some(EnforcementDecision::Denied {\n    78\t                    tool_name: tool_name.clone(),\n    79\t                    reason: reason.clone(),\n    80\t                });\n    81\t                self.inner.emit(event);\n    82\t            }\n    83\t            LoopAuditEvent::ToolCallRequested { tool_name, .. }\n    84\t                if !tool_allowed(tool_name, &self.allowlist) =>\n    85\t            {\n    86\t                let reason = format!(\"tool `{tool_name}` not in allowlist\");\n    87\t                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {\n    88\t                    tool_name: tool_name.clone(),\n    89\t                    reason: reason.clone(),\n    90\t                });\n    91\t                self.inner.emit(event);\n    92\t                let denial = LoopAuditEvent::PolicyDenial {\n    93\t                    ts: chrono::Utc::now(),\n    94\t                    run_id: self.run_id.clone(),\n    95\t                    session_id: self.session_id.clone(),\n    96\t                    iteration: 0,\n    97\t                    tool_name: tool_name.clone(),\n    98\t                    reason: reason.clone(),\n    99\t                };\n   100\t                self.inner.emit(&denial);\n   101\t                *self.tripped.lock().expect(\"tripped mutex\") = Some(EnforcementDecision::Denied {\n   102\t                    tool_name: tool_name.clone(),\n   103\t                    reason,\n   104\t                });\n   105\t            }\n   106\t            _ => self.inner.emit(event),\n   107\t        }\n   108\t    }\n   109\t\n   110\t    fn write_blob(&self, content: &[u8]) -> String {\n","exit_code":0,"status":"completed"}}
