lone(),\n                    session_id: self.session_id.clone(),\n                    iteration: 0,\n                    tool_name: tool_name.clone(),\n                    reason: reason.clone(),\n                };\n                self.inner.emit(&denial);\n                *self.tripped.lock().expect(\"tripped mutex\") = Some(EnforcementDecision::Denied {\n                    tool_name: tool_name.clone(),\n                    reason,\n                });\n            }\n            _ => self.inner.emit(event),\n        }\n    }"}","structuredContent":{"children":[],"lineage":["dir:crates/orbit-engine/src/activity_job","file:crates/orbit-engine/src/activity_job/tool_enforcement.rs"],"lines":[56,108],"selector":"symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink::emit:method","siblings":["symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcementDecision:struct","symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink:struct","symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink::new:method"],"source":"fn emit(&self, event: &LoopAuditEvent) {
        // Two paths can trigger the denial:
        //
        // 1. `AgentLoop` enforces the allowlist internally BEFORE dispatching
        //    a `ToolCallRequested` event and emits its own `PolicyDenial`.
        //    When we see a `PolicyDenial`, we mirror it into a §7
        //    `tool.denied` envelope event so the higher-level trail records
        //    the policy outcome alongside the loop-level event.
        //
        // 2. A caller that bypasses the loop's own check could still emit a
        //    `ToolCallRequested` for a tool we shouldn't allow — we catch
        //    that here too and synthesize both a §7 `tool.denied` envelope
        //    event and a loop-level `PolicyDenial`.
        match event {
            LoopAuditEvent::PolicyDenial {
                tool_name, reason, ..
            } => {
                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                self.inner.emit(event);
            }
            LoopAuditEvent::ToolCallRequested { tool_name, .. }
                if !tool_allowed(tool_name, &self.allowlist) =>
            {
                let reason = format!("tool `{tool_name}` not in allowlist");
                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                self.inner.emit(event);
                let denial = LoopAuditEvent::PolicyDenial {
                    ts: chrono::Utc::now(),
                    run_id: self.run_id.clone(),
                    session_id: self.session_id.clone(),
                    iteration: 0,
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                };
                self.inner.emit(&denial);
                *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                    tool_name: tool_name.clone(),
                    reason,
                });
            }
            _ => self.inner.emit(event),
        }
    }"}}}
